  ('elementary-64311456-moex-00758', 'elementary-64311456', 'elementary-64311456-moex-111-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '有關強制性團體的敘述，下列何者錯誤？', '["又稱為非自治團體", "比較不考慮成員的期待", "精神科病患家屬所組成的團體是屬於此類型", "成員一開始容易表現沉默，甚至不合作的態度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "2fbac3fb0314", "answer_pdf_sha1": "ec43feddf564", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
