  ('elementary-64311456-moex-00760', 'elementary-64311456', 'elementary-64311456-moex-111-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '有關社會個案工作者角色的敘述，下列何者錯誤？', '["使能者／諮商者的角色：協助案主改變行為的使能者，積極透過傾聽、同理案主的情境，發揮諮商者 的角色", "諮詢者／教育者的角色：提供案主專門知識或訊息的諮詢者，運用教導技巧協助案主如何瞭解和處理 自己的問題", "調停者／仲介者的角色：當處理個案問題時，發現他們有因權利被剝奪而產生共同的問題，於是透過 社會行動方式，促成問題解決", "個案管理者：當案主有複雜而嚴重的問題時，需要轉介或連結不同資源，並監督服務輸送，使嚴重問 題得以改善"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "2fbac3fb0314", "answer_pdf_sha1": "ec43feddf564", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00761', 'elementary-64311456', 'elementary-64311456-moex-111-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '目前在社區議題中推動的參與式預算，是屬於下列那一種理念的實踐？', '["審議民主在社區參與的實踐", "社區需求在社區理念的實踐", "社區培力在社區能力的實踐", "社區服務在社區資源的實踐"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "2fbac3fb0314", "answer_pdf_sha1": "ec43feddf564", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00762', 'elementary-64311456', 'elementary-64311456-moex-111-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '有關「治療會談」的敘述，下列何者正確？', '["治療會談是在服務計畫確定後，較完整而有步驟地完成服務目標", "研判焦點問題後，提供案主所需之服務", "為了得到案主個人或社會問題的背景、問題史", "建立對事實的建構，以引導介入方向"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "2fbac3fb0314", "answer_pdf_sha1": "ec43feddf564", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00763', 'elementary-64311456', 'elementary-64311456-moex-111-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '有關婚姻暴力之敘述，下列何者錯誤？', '["婚姻暴力事件的當事人並非全是低社經地位和族群的問題", "婚姻暴力的行為包括肢體暴力、性暴力和精神暴力", "婚姻暴力事件僅對當事人有影響", "國人在婚姻暴力事件後，尋求外界的協助多數以家人與朋友為主"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "2fbac3fb0314", "answer_pdf_sha1": "ec43feddf564", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00764', 'elementary-64311456', 'elementary-64311456-moex-111-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '有關社會工作者在災害準備及災後生活重建各階段的角色與職責，下列敘述何者錯誤？', '["在災難預防期，進行風險評估與防災教育", "在災難整備期，進行防災與救災人員的組訓與演練", "在災難應變期，治療罹患創傷後壓力症候群的災民", "在災後復原期，協助災民澄清對新家園的重建計畫，透過討論及交流將意見表達並完成重建"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "2fbac3fb0314", "answer_pdf_sha1": "ec43feddf564", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL)
